import React from "react";
import { useDispatch, useSelector } from "react-redux";
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome";
import { faCarrot, faRotateRight, faSpinner, faTrash } from "@fortawesome/free-solid-svg-icons";
import { createPantryItem, deletePantryItem, fetchPantryItems } from "./pantrySlice";

const categories = ["protein", "produce", "grain", "dairy", "spice", "pantry", "other"];

const units = [
  { value: "", label: "No unit" },
  { value: "pcs", label: "pcs" },
  { value: "g", label: "grams (g)" },
  { value: "kg", label: "kilograms (kg)" },
  { value: "oz", label: "ounces (oz)" },
  { value: "lb", label: "pounds (lb)" },
  { value: "ml", label: "milliliters (ml)" },
  { value: "l", label: "liters (l)" },
  { value: "tsp", label: "teaspoons (tsp)" },
  { value: "tbsp", label: "tablespoons (tbsp)" },
  { value: "cup", label: "cups" },
  { value: "can", label: "cans" },
  { value: "pack", label: "packs" },
  { value: "bag", label: "bags" },
  { value: "bottle", label: "bottles" },
  { value: "clove", label: "cloves" },
  { value: "slice", label: "slices" },
];

export default function PantryPage() {
  const dispatch = useDispatch();
  const { items, status, saveStatus, deleteStatus, error } = useSelector((state) => state.pantry);
  const [form, setForm] = React.useState({ name: "", category: "produce", quantity: "", unit: "" });
  const isLoading = status === "loading";
  const isSaving = saveStatus === "loading";
  const isDeleting = deleteStatus === "loading";

  function updateField(event) {
    setForm((current) => ({ ...current, [event.target.name]: event.target.value }));
  }

  async function handleSubmit(event) {
    event.preventDefault();
    if (!form.name.trim()) return;

    try {
      await dispatch(createPantryItem(form)).unwrap();
      setForm({ name: "", category: "produce", quantity: "", unit: "" });
    } catch {
      // The slice stores the user-facing error message.
    }
  }

  return (
    <div className="page-stack">
      <div className="page-heading">
        <p className="eyebrow">Pantry manager</p>
        <h2>Ingredients on hand</h2>
        <p>Add the ingredients the AI chef can use when creating recipe suggestions.</p>
      </div>

      {error && (
        <div className="error-banner">
          {error}
          <button className="secondary-button" type="button" onClick={() => dispatch(fetchPantryItems())}>
            <FontAwesomeIcon icon={faRotateRight} /> Retry
          </button>
        </div>
      )}

      <form className="card form-grid" onSubmit={handleSubmit}>
        <label>
          Ingredient
          <input name="name" value={form.name} onChange={updateField} placeholder="e.g. lettuce" maxLength="40" disabled={isSaving} />
        </label>
        <label>
          Category
          <select name="category" value={form.category} onChange={updateField} disabled={isSaving}>
            {categories.map((category) => (
              <option key={category} value={category}>{category}</option>
            ))}
          </select>
        </label>
        <label>
          Quantity
          <input name="quantity" value={form.quantity} onChange={updateField} placeholder="2" disabled={isSaving} />
        </label>
        <label>
          Unit
          <select name="unit" value={form.unit} onChange={updateField} disabled={isSaving}>
            {units.map((unit) => (
              <option key={unit.value} value={unit.value}>{unit.label}</option>
            ))}
          </select>
        </label>
        <button className="primary-button" type="submit" disabled={isSaving || !form.name.trim()}>
          <FontAwesomeIcon icon={isSaving ? faSpinner : faCarrot} spin={isSaving} />
          {isSaving ? "Adding..." : "Add item"}
        </button>
      </form>

      <div className="card list-card">
        {isLoading && <p className="empty-state">Loading pantry items...</p>}
        {!isLoading && items.length === 0 && <p className="empty-state">No pantry items yet.</p>}
        {items.map((item) => (
          <div className="list-row" key={item.id}>
            <div>
              <strong>{item.name}</strong>
              <span>{item.category} {item.quantity && `- ${item.quantity} ${item.unit}`}</span>
            </div>
            <button className="icon-button danger" type="button" onClick={() => dispatch(deletePantryItem(item.id))} aria-label={`Remove ${item.name}`} disabled={isDeleting}>
              <FontAwesomeIcon icon={isDeleting ? faSpinner : faTrash} spin={isDeleting} />
            </button>
          </div>
        ))}
      </div>
    </div>
  );
}
